basicnumber.script:
function onInit()
	super.onInit();
	local nodeChar = window.getDatabaseNode();
	DB.addHandler(DB.getPath(nodeChar, "abilities"), "onChildUpdate", onSourceUpdate);
	DB.addHandler(DB.getPath(nodeChar, "defenses.ac.temporary"), "onUpdate", onSourceUpdate);
	DB.addHandler(DB.getPath(nodeChar, "defenses.ac.base"), "onUpdate", onSourceUpdate);
	DB.addHandler(DB.getPath(nodeChar, "defenses.ac.armor"), "onUpdate", onSourceUpdate);
	DB.addHandler(DB.getPath(nodeChar, "defenses.ac.shield"), "onUpdate", onSourceUpdate);
	DB.addHandler(DB.getPath(nodeChar, "defenses.ac.misc"), "onUpdate", onSourceUpdate);
	onSourceUpdate();
end
function onClose()
	local nodeChar = window.getDatabaseNode();
	DB.removeHandler(DB.getPath(nodeChar, "abilities"), "onChildUpdate", onSourceUpdate);
	DB.removeHandler(DB.getPath(nodeChar, "defenses.ac.temporary"), "onUpdate", onSourceUpdate);
	DB.removeHandler(DB.getPath(nodeChar, "defenses.ac.base"), "onUpdate", onSourceUpdate);
	DB.removeHandler(DB.getPath(nodeChar, "defenses.ac.armor"), "onUpdate", onSourceUpdate);
	DB.removeHandler(DB.getPath(nodeChar, "defenses.ac.shield"), "onUpdate", onSourceUpdate);
	DB.removeHandler(DB.getPath(nodeChar, "defenses.ac.misc"), "onUpdate", onSourceUpdate);
end
function onSourceUpdate()
	local nodeChar = window.getDatabaseNode();
	local nAcks = 0;
	if AttackThrowManager and AttackThrowManager.getPCAcksAC then
		nAcks = AttackThrowManager.getPCAcksAC(nodeChar);
	else
		local rActor = ActorManager.resolveActor(nodeChar);
		local nDex = ActorManagerADND.getAbilityBonus(rActor, "dexterity", "defenseadj") or 0;
		local nDesc = nDex
			+ DB.getValue(nodeChar, "defenses.ac.temporary", 0)
			+ DB.getValue(nodeChar, "defenses.ac.base", 10)
			+ DB.getValue(nodeChar, "defenses.ac.armor", 0)
			+ DB.getValue(nodeChar, "defenses.ac.shield", 0)
			+ DB.getValue(nodeChar, "defenses.ac.misc", 0);
		nAcks = 10 - nDesc;
	end
	-- Write display value; also mirror into total so CT/tooltips match ACKS
	setValue(nAcks);
end

number_charthaco_charsheet.script:
function onInit()
	if super and super.onInit then
		super.onInit();
	end
	local node = window.getDatabaseNode();
	if AttackThrowManager and AttackThrowManager.syncNode then
		AttackThrowManager.syncNode(node);
	end
end

number_columnh.script:
function onInit()
	if super and super.onInit then
		super.onInit();
	end
	local node = window.getDatabaseNode();
	if AttackThrowManager and AttackThrowManager.syncNode then
		AttackThrowManager.syncNode(node);
	end
end
function onValueChanged()
	if AttackThrowManager and AttackThrowManager.isSyncing and AttackThrowManager.isSyncing() then
		return;
	end
	local node = window.getDatabaseNode();
	if not node then
		return;
	end
	DB.setValue(node, "attackthrow_manual", "number", 1);
	local nThrow = getValue();
	DB.setValue(node, "thaco", "number", 10 + nThrow);
	if window.onSummaryChanged then
		window.onSummaryChanged();
	end
end

local bInternal = false;
function onInit()
	if super and super.onInit then
		super.onInit();
	end
	local node = window.getDatabaseNode();
	DB.addHandler(DB.getPath(node, "ac"), "onUpdate", onDBUpdate);
	refreshFromDB();
end
function onClose()
	local node = window.getDatabaseNode();
	DB.removeHandler(DB.getPath(node, "ac"), "onUpdate", onDBUpdate);
end
function onDBUpdate()
	if bInternal then
		return;
	end
	refreshFromDB();
end
function toAcks(nDesc)
	if AttackThrowManager and AttackThrowManager.descendingToAcks then
		return AttackThrowManager.descendingToAcks(nDesc);
	end
	return 10 - (tonumber(nDesc) or 10);
end
function toDesc(nAcks)
	if AttackThrowManager and AttackThrowManager.acksToDescending then
		return AttackThrowManager.acksToDescending(nAcks);
	end
	return 10 - (tonumber(nAcks) or 0);
end
function refreshFromDB()
	local node = window.getDatabaseNode();
	local nDesc = DB.getValue(node, "ac", 10);
	local nAcks = toAcks(nDesc);
	bInternal = true;
	setValue(nAcks);
	-- If source-binding wrote ACKS into ac, restore descending
	if DB.getValue(node, "ac", 10) ~= nDesc then
		DB.setValue(node, "ac", "number", nDesc);
	end
	bInternal = false;
end
function onValueChanged()
	if bInternal then
		return;
	end
	local node = window.getDatabaseNode();
	local nAcks = getValue();
	local nDesc = toDesc(nAcks);
	bInternal = true;
	DB.setValue(node, "ac", "number", nDesc);
	setValue(nAcks);
	bInternal = false;
	if window.onSummaryChanged then
		window.onSummaryChanged();
	end
end

windowclass.script:
function onSummaryChanged()
	if super and super.onSummaryChanged then
		super.onSummaryChanged();
	end
	if summary_label then
		local s = summary_label.getValue() or "";
		s = string.gsub(s, "THACO:%s*(%-?%d+)", "Throw: %1+");
		-- Summary still pulls raw DB ac (descending); rewrite as ACKS
		local node = getDatabaseNode();
		if node then
			local nDesc = DB.getValue(node, "ac", 10);
			local nAcks = 10 - nDesc;
			s = string.gsub(s, "AC:%s*" .. tostring(nDesc), "AC: " .. tostring(nAcks));
		end
		summary_label.setValue(s);
	end
end

button_turnundead.script:
function onInit()
	DB.addHandler(DB.getPath(window.getDatabaseNode(), "turn.total"), "onUpdate", onValueChanged);
	onValueChanged();
end
function onClose()
	DB.removeHandler(DB.getPath(window.getDatabaseNode(), "turn.total"), "onUpdate", onValueChanged);
end
function onValueChanged()
	local nTLevel = DB.getValue(window.getDatabaseNode(), "turn.total", 0);
	local bShow = (nTLevel > 0);
	setVisible(bShow);
	window.label_turnlevel.setVisible(bShow);
end
